import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import javax.annotation.PostConstruct;

@Service
public class InitDemoService {
    @Value("${app.name:ProductService}")
    private String name;

    public InitDemoService() {
        // @Value not yet injected at constructor time:
        System.out.println("Constructor: name = " + name);  // null!
    }

    @PostConstruct
    public void init() {
        // @Value is now injected:
        System.out.println("PostConstruct: name = " + name);  // ProductService
    }
}

