// DiscountService depends on PricingRepository
interface PricingRepository { double getDiscountRate(int qty); }

@Service
class DiscountService {
    private final PricingRepository pricingRepo;
    DiscountService(PricingRepository repo) { this.pricingRepo = repo; }
    double calculate(int qty, double price) {
        double rate = pricingRepo.getDiscountRate(qty);
        return qty * price * (1 - rate);
    }
}

