// StockPriceService.java:
import org.springframework.stereotype.Service;
import javax.annotation.PostConstruct;
import java.util.*;
@Service
public class StockPriceService {
    private final CacheService cache;
    StockPriceService(CacheService cache) { this.cache = cache; }
    @PostConstruct void init() {
        System.out.println("StockPriceService initialized");
        cache.put("TCS", 3890.0); cache.put("RELIANCE", 2450.0);
    }
    public Map<String, Double> getPrices() {
        Map<String, Double> prices = new HashMap<>();
        List.of("TCS","RELIANCE").forEach(s -> cache.get(s).ifPresent(p -> prices.put(s, p)));
        return prices;
    }
}

