import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import javax.annotation.PostConstruct;
@Service
public class PaymentConfigService {
    @Value("${payment.enabled:false}") private boolean enabled;
    @Value("${payment.max-amount:50000}") private int maxAmount;
    @Value("${payment.currency:INR}") private String currency;
    @Value("${payment.provider:razorpay}") private String provider;

    @PostConstruct
    void validate() {
        if (maxAmount <= 0) throw new IllegalStateException("Max amount must be positive");
        System.out.println("Payment config: " + provider + " (" + currency + ") max=" + maxAmount);
    }
    public boolean isEnabled() { return enabled; }
    public int getMaxAmount()   { return maxAmount; }
    public String getCurrency() { return currency; }
    public String getProvider() { return provider; }
}

// PaymentGatewayService.java:
import org.springframework.stereotype.Service;
@Service
public class PaymentGatewayService {
    private final PaymentConfigService config;
    PaymentGatewayService(PaymentConfigService config) { this.config = config; }
    public boolean isEnabled()      { return config.isEnabled(); }
    public boolean canProcess(double amount) { return isEnabled() && amount <= config.getMaxAmount(); }
}

